var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 인물 과거 조사","JPN":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3級要人</color>閲覧承認資料\\n付録：人物の過去調査","ENG":"SCN No. TPM001M000139-05\\n<color=#ffd34c>Clearance Level III</color> Classified Information\\nAnnex: Personal Background Investigation Results","TWN":"SCN No.TPM001M000139-05\\n<color=#ffd34c>3級要員</color> 閱覽審批資料\\n附錄人物過往調查"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아! 오늘 컨디션 나쁘지 않은데? 또 기록을 갱신했다고!","JPN":"よし！　今日も調子がいいな！　また記録を更新したぞ！","ENG":"Great! You must be in tiptop shape today! You just broke the record again!","TWN":"漂亮！今天狀態不錯啊？又刷新了記錄！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"신예치곤 굉장하구만. 이 정도면 시즌우승컵도 노려 볼만 하겠는데?","JPN":"新人なのにすごいな。この調子なら、シーズンの優勝も狙えそうだ。","ENG":"That's pretty impressive for someone new. At this rate, we could even aim for the season championship.","TWN":"以新人來說真是了不起，這種程度的話，應該有拿下季賽冠軍的潛力吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 감독님!","JPN":"ありがとうございます、監督！","ENG":"Thanks, Director!","TWN":"謝謝你，教練！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"너무 추켜세워주지 마시죠, 선수 버릇 나빠집니다.","JPN":"調子に乗ると困るので、ほどほどにしてください。","ENG":"Go easy on the praise, Director. You'll spoil him.","TWN":"不要太吹捧他啦，選手養出壞習慣來的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"하하, 이 사람아. 칭찬 아껴뒀다 뭐에 쓰게?","JPN":"はは、そう言うな。俺は褒めて伸ばすタイプなんだ。","ENG":"Aw, come on. You've got to give praise where praise is due.","TWN":"哈哈，你這個人。這麼捨不得誇獎別人，是會少塊肉嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"이 기세라면 코스레코드 경신도 꿈은 아니지.","JPN":"この調子なら、コースレコードの更新も夢じゃない。","ENG":"At this rate, breaking the course record might just be within reach.","TWN":"照這個氣勢下去，要更新最快圈速也不是夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"그건 무리일 겁니다. 두 번째라면 뭐...... 가능성이 있지만요.","JPN":"それは無理だと思います。でも2位なら、まあ……","ENG":"I doubt it. Maybe second place, sure... That's feasible enough.","TWN":"那不可能吧。不過第二名……那倒是還有可能。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"하긴 그건 그렇지.","JPN":"それはそうだな。","ENG":"I suppose you're right.","TWN":"也是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"코스레코드...... 그러고 보니 저번에 보여주신 그 기록은 대체 뭔가요?","JPN":"コースレコード……そういえば、この前見せてくださった記録は、一体何ですか？","ENG":"Course record... Speaking of which, what was that other record you showed me last time?","TWN":"最快圈速……話說上次看到的那個記錄到底是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"뭐긴? 그야, 말 그대로 이 서킷에서 세워진 최고기록이지.","JPN":"もちろん、そのサーキットでの最高記録だ。","ENG":"What else would it be? It's the highest record from this circuit.","TWN":"還能是什麼？就是字面意思，在這個賽車場上創下的最高紀錄啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"하지만 제가 알고 있는 바로는 우승자들 중에서도 그런 기록을 세운 사람은 없었는데요.","JPN":"しかし、俺が知る限りでは優勝者の中にも、これほどの記録を残した人はいません。","ENG":"But as far as I know, not even any of the champions have a record like that.","TWN":"但就我所知，獲勝者中沒有人創下過這樣的記錄啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"그야 타임 트라이얼에서 세운 비공식 기록이니까.","JPN":"そりゃあ、タイムトライアルでの非公式記録だからだ。","ENG":"That's because it was an unofficial record broken during the time trial.","TWN":"因為那是在計時賽創下的非官方記錄。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"꽤 예전 일이라서 자넨 누군지도 모를 걸?","JPN":"かなり前のことだから、お前は知らないはずだ。","ENG":"It was from quite a while ago, so you probably don't even know who that was.","TWN":"很久以前的事情了，你應該都不知道那是誰吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"제가 모르는 사람이라고요? 그 엄청난 기록이?","JPN":"あんなすごい記録を残してるのに、俺が知らないなんて……","ENG":"It's someone I don't know? Whoever broke that incredible record?","TWN":"一個我不知道的人？創下了那個驚人的記錄？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"굉장히 젊은 선수였는데, 이미 한참 전에 은퇴했거든.","JPN":"すごく若い選手だったが、ずいぶん前に引退したんだ。","ENG":"It was a very young driver, but she retired a long time ago.","TWN":"她是一位非常年輕的選手，但很久前就已經退役了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"이런...... 복귀가 어려울 정도로 큰 사고였나요?","JPN":"ああ……復帰できないほどの事故だったんですか？","ENG":"Oh dear... Did she get into an accident so bad that she couldn't drive again?","TWN":"怎麼會……是發生了什麼嚴重的事故，受了重傷嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"아니? 멀쩡하게 제 발로 뛰쳐나갔다.","JPN":"いや？　何事もなかったぞ？","ENG":"Uh, not actually. She walked away on her own two feet.","TWN":"沒有啦，她是用自己健全的雙腿跑掉的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"자긴 온로드 서킷보다 거친 아스팔트가 좋다면서 말이야.","JPN":"そいつが引退した理由は、オンロードサーキットよりアスファルトの方が好きだからだ。","ENG":"Apparently she prefers the rough urban asphalt to the racing tracks.","TWN":"比起平坦的賽道，她說她更喜歡粗糙的瀝青路面。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"으하하, 지금 생각해도 참 웃긴 애라니까.","JPN":"わはは、本当におもしろいやつだよな。","ENG":"Hah hah, the more I think about her, the more ridiculous it all sounds.","TWN":"哈哈哈，現在想想都覺得好笑。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"그런 터무니없는 기록을 세워놓고선 나 몰라라 떠나버리다니.","JPN":"あんな記録を残して、去っちまうなんて。","ENG":"She set a crazy record like that only to leave it all behind.","TWN":"在創下了那個誇張紀錄後，竟然就這樣不為人知地隱退了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"덕분에 한동안 이 서킷에서 훈련하던 친구들이 단체로 슬럼프가 왔지.","JPN":"おかげで、このサーキットで訓練してたやつらが、一斉にスランプに陥った。","ENG":"Thanks to her, everyone who trained on this circuit fell into a slump for a while.","TWN":"托她的福，在這賽車場中練習的朋友們，有段時間全都陷入低潮。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"도저히 그 기록을 따라잡을 수 없다는 박탈감 때문에 말이야.","JPN":"どう足掻いても、あの記録を破るのは無理だからな。","ENG":"They just didn't think they'd ever catch up to a record like that.","TWN":"因為根本無法打破的紀錄所帶來的剝奪感。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"아스팔트라면...... 공도 레이싱으로 전향한 건가요?","JPN":"アスファルトなら……公道レースに転向したんですか？","ENG":"Urban asphalt, huh? Did she switch to street racing?","TWN":"瀝青……難道她是朝公路賽車發展了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"글쎄. 이미 우리 손을 떠났는데 지금 뭘 하고 있는지 알 턱이 있나?","JPN":"さあな。俺もそこまではわからない。","ENG":"Not sure. She's already out of our hair. How would I know what she's been up to?","TWN":"誰知道呢。她已經離開這麼久了，我怎麼可能知道她現在在做什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"그래도 그런 불법적인 짓은 안 할 거다.","JPN":"だが、違法レースには手を出してないはずだ。","ENG":"But she wouldn't do anything illegal like that.","TWN":"不過她不會幹什麼違法的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"선을 지킬 줄 아는 영리한 친구였거든.","JPN":"一線を越えない賢いやつだったからな。","ENG":"She was a smart cookie, who always knew where to draw the line.","TWN":"畢竟她是個不會越線的聰明朋友呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"아, 그 분 얘기라면 얼마 전에 건너건너 들은 적이 있어요.","JPN":"あ、その方の話なら、人づてに聞きましたよ。","ENG":"Oh, I think I heard about her through the grapevine the other day.","TWN":"啊，你們在說那個人的話，我前陣子有聽說過她的消息喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"오 그래? 지금 대체 뭘 한다던가?","JPN":"へえ？　今は何をしてるんだ？","ENG":"Oh, really? So what's she been up to?","TWN":"哦，是嗎？那她現在到底在做什麼啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"하하, 그게 실은...... 경찰이 됐다고 하더군요. 벌써 경위까지 달았다는데요?","JPN":"はは、それが……警察になったそうです。もう警部補になったらしいですよ？","ENG":"Hah hah, well... She became a cop, apparently. She's already a lieutenant, they say!","TWN":"哈哈，事實上……她說她成為了一位警察，而且已經當到警衛了。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"잘 이해가 안 되네요. 코스 레코드까지 세운 천재 유망주가 왜 갑자기 경찰을......","JPN":"よくわかりません。コースレコードを塗り替えた天才が、なぜ警察に……","ENG":"I don't get it. Why would a record-breaking genius suddenly become a cop?","TWN":"真是無法理解呢。創下最快圈速的新星天才，為什麼會突然去當警察……"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐, 서킷 위에서도 언제나 예상을 엇나가던 친구였으니까.","JPN":"まあ、サーキットの上でも予想を裏切ってたからな。","ENG":"Well, she was always unpredictable, even on the racetrack.","TWN":"這個嘛，畢竟她是個就算在賽道上，也老是會做出一些驚人之舉的朋友。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"자기 나름대로의 생각이 있었던 거겠지.","JPN":"きっと自分なりの考えがあったんだろう。","ENG":"She probably had her reasons.","TWN":"她應該有自己的想法吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"정해진 길을 쫓아가는 것보단, 모험을 좋아하는 녀석이었거든.","JPN":"決められた道を走るより、冒険を好むやつだったし。","ENG":"She was always more interested in adventures than following a set path.","TWN":"她是比起被決定好的道路，更喜歡冒險的人。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"너무 거창하게 포장하는 거 아닙니까?","JPN":"本当にそうでしょうか？","ENG":"Aren't you giving her too much credit?","TWN":"你是不是太美化她了？"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENIOR_NPC_NULL_NULL","text":{"KOREA":"그냥 경찰차를 타고 있으면 과속딱지를 떼일 일이 없다거나, 그런 이유겠죠, 뭐.","JPN":"パトカーならスピード違反で切符を切られないからとか……意外とそういう、くだらない理由かもしれませんよ？","ENG":"She probably just figured she wouldn't get a speeding ticket in her patrol car or something.","TWN":"她只是因為開警車就不會被開罰單，就這樣的理由而已啦，真是的。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"어허, 애를 너무 바보 취급하는 거 아냐?","JPN":"いやいや。いくら何でも、それはないだろ？","ENG":"Oh, come on. She's not that stupid.","TWN":"喂，你是不是把她當成笨蛋了？"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"그런 이유로 경찰이 되려는 사람이 있겠어?","JPN":"そんな理由で警察になるやつがどこにいる。","ENG":"Nobody would become a cop over something like that!","TWN":"怎麼可能會有人會因為那種理由當警察？"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRIVER_NPC_NULL_NULL","text":{"KOREA":"......감독님. 혹시 그 선배, 이름을 기억하시나요?","JPN":"……監督。その先輩の名前、覚えてますか？","ENG":"Director... Would you happen to remember her name?","TWN":"……教練。你還記得那位前輩的名字嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"흔한 이름이야. 강소영이라고.","JPN":"よくある名前だよ。マエカワ・ナツミって言うんだ。","ENG":"It's a pretty common name. Kang Soyoung.","TWN":"是個很常見的名字，叫姜素英。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 그 애가 달리는 모습을 한 번이라도 봤다면, 결코 잊을 수 없게 되지.","JPN":"だが、そいつが走る姿を一度でも目にしたら、決して忘れられないはずだ。","ENG":"But if you ever see her racing, you won't forget her name at all.","TWN":"不過，你只要看到她急駛的身影，就絕對不會忘掉這個名字。"},"stage":{"bg":"BLACK","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};